const count = query.count || 1;
const company = query.company || '';
const topic = query.topic || '';
const platform = (query.platform || 'leetcode').toLowerCase();
const LEETCODE_USER = 'Kamani_Dev_S';
const CODEFORCES_USER = 'devkamani9313';

try {
  const localSolvedRes = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://localhost:3000/api/dsa/solved',
    qs: {
      chat_id: $('Execute Workflow Trigger').first().json.chat_id,
      platform: platform
    },
    json: true
  });
  const solvedSet = new Set((localSolvedRes.data || []).map(s => s.toLowerCase()));

  if (platform === 'codeforces') {
    const userStatus = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://codeforces.com/api/user.status?handle=${CODEFORCES_USER}`,
      json: true
    });

    if (userStatus.status === 'OK') {
      userStatus.result.forEach(sub => {
        if (sub.verdict === 'OK' && sub.problem) {
          solvedSet.add(`${sub.problem.contestId}-${sub.problem.index}`.toLowerCase());
          if (sub.problem.name) solvedSet.add(sub.problem.name.toLowerCase());
        }
      });
    }

    const probData = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://codeforces.com/api/problemset.problems',
      json: true
    });

    if (probData.status !== 'OK') {
      return 'Error fetching Codeforces problems';
    }

    let problems = probData.result.problems || [];

    if (topic) {
      const normTopic = topic.toLowerCase().trim();
      problems = problems.filter(p => (p.tags || []).some(t => {
        const normTag = t.toLowerCase().trim();
        return normTag.includes(normTopic) || normTopic.includes(normTag);
      }));
    }

    problems = problems.filter(p => {
      const codeKey = `${p.contestId}-${p.index}`.toLowerCase();
      const nameKey = p.name ? p.name.toLowerCase() : '';
      return !solvedSet.has(codeKey) && !solvedSet.has(nameKey);
    });
    problems = problems.sort(() => 0.5 - Math.random());

    const selected = problems.slice(0, count).map(p => ({ 
      platform: 'Codeforces',
      title: p.name,
      difficulty: p.rating ? `${p.rating} (Rating)` : 'Unknown',
      link: `https://codeforces.com/problemset/problem/${p.contestId}/${p.index}`,
      tags: p.tags || []
    }));

    return JSON.stringify(selected);
  } else {
    const acData = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://alfa-leetcode-api.onrender.com/${LEETCODE_USER}/acSubmission`,
      json: true
    });
    (acData.submission || []).forEach(s => {
      if (s.titleSlug) solvedSet.add(s.titleSlug.toLowerCase());
      if (s.title) solvedSet.add(s.title.toLowerCase());
    });

    let normalizedTopic = topic.toLowerCase().trim().replace(/[\s-_]+/g, '');
    let searchTags = [];
    let requireMatrix = false;
    if (normalizedTopic.includes('dp') || normalizedTopic.includes('dynamicprogramming')) {
      searchTags.push('dynamic-programming');
      if (normalizedTopic.includes('grid') || normalizedTopic.includes('matrix')) {
        requireMatrix = true;
      }
    } else if (normalizedTopic.includes('graph')) {
      searchTags.push('graph');
    } else if (normalizedTopic.includes('tree')) {
      if (normalizedTopic.includes('bst') || normalizedTopic.includes('search')) {
        searchTags.push('binary-search-tree');
      } else {
        searchTags.push('tree', 'binary-tree');
      }
    } else if (normalizedTopic.includes('string')) {
      searchTags.push('string');
    } else if (normalizedTopic.includes('array')) {
      searchTags.push('array');
    } else if (normalizedTopic.includes('linkedlist')) {
      searchTags.push('linked-list');
    } else if (normalizedTopic.includes('binarysearch')) {
      searchTags.push('binary-search');
    } else if (normalizedTopic.includes('slidingwindow')) {
      searchTags.push('sliding-window');
    } else if (normalizedTopic.includes('pointer')) {
      searchTags.push('two-pointers');
    } else if (normalizedTopic) {
      searchTags.push(topic.toLowerCase().trim().replace(/\s+/g, '-'));
    }

    const tag = searchTags[0] || '';
    const gqlQuery = `
      query problemsetQuestionList($categorySlug: String, $limit: Int, $skip: Int, $filters: QuestionListFilterInput) {
        problemsetQuestionList: questionList(
          categorySlug: $categorySlug
          limit: $limit
          skip: $skip
          filters: $filters
        ) {
          total: totalNum
          questions: data {
            title
            titleSlug
            difficulty
            topicTags {
              slug
            }
          }
        }
      }
    `;

    const firstPageRes = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://leetcode.com/graphql',
      headers: {
        'content-type': 'application/json',
        'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
      },
      body: {
        query: gqlQuery,
        variables: {
          categorySlug: '',
          limit: 100,
          skip: 0,
          filters: tag ? { tags: [tag] } : {}
        }
      },
      json: true
    });

    const totalProblems = firstPageRes.data?.problemsetQuestionList?.total || 0;
    let problems = firstPageRes.data?.problemsetQuestionList?.questions || [];

    if (totalProblems > 100) {
      const skipOffsets = [];
      for (let skip = 100; skip < totalProblems; skip += 100) {
        skipOffsets.push(skip);
      }

      const fetchPromises = skipOffsets.map(skip => {
        return this.helpers.httpRequest({
          method: 'POST',
          url: 'https://leetcode.com/graphql',
          headers: {
            'content-type': 'application/json',
            'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
          },
          body: {
            query: gqlQuery,
            variables: {
              categorySlug: '',
              limit: 100,
              skip: skip,
              filters: tag ? { tags: [tag] } : {}
            }
          },
          json: true
        });
      });

      const pageResults = await Promise.all(fetchPromises);
      pageResults.forEach(res => {
        const list = res.data?.problemsetQuestionList?.questions || [];
        problems = problems.concat(list);
      });
    }

    const filtered = problems.filter(p => {
      const slugKey = p.titleSlug ? p.titleSlug.toLowerCase() : '';
      const titleKey = p.title ? p.title.toLowerCase() : '';
      if (solvedSet.has(slugKey) || solvedSet.has(titleKey)) return false;

      if (requireMatrix) {
        const hasMatrixTag = (p.topicTags || []).some(t => t.slug === 'matrix' || t.slug === 'array');
        const title = p.title.toLowerCase();
        const matchesKeyword = title.includes('path') || title.includes('grid') || title.includes('matrix') || title.includes('square') || title.includes('dungeon') || title.includes('cherry');
        return hasMatrixTag || matchesKeyword;
      }
      return true;
    });

    let selectedProblems = filtered;
    if (selectedProblems.length === 0 && requireMatrix) {
      selectedProblems = problems.filter(p => {
        const slugKey = p.titleSlug ? p.titleSlug.toLowerCase() : '';
        const titleKey = p.title ? p.title.toLowerCase() : '';
        return !solvedSet.has(slugKey) && !solvedSet.has(titleKey);
      });
    }

    if (company) {
      selectedProblems = selectedProblems.sort(() => 0.5 - Math.random());
    }

    const selected = selectedProblems.slice(0, count).map(p => ({ 
      platform: 'LeetCode',
      title: p.title,
      difficulty: p.difficulty,
      link: `https://leetcode.com/problems/${p.titleSlug}/`
    }));

    return JSON.stringify(selected);
  }
} catch (e) {
  return 'Error fetching problem: ' + e.message;
}

try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://codeforces.com/api/contest.list',
    json: true
  });
  if (data.status !== 'OK') return 'Error from Codeforces API';

  let upcoming = data.result.filter(c => c.phase === 'BEFORE').reverse();
  upcoming = upcoming.slice(0, 5);

  const schedule = upcoming.map(c => {
    const date = new Date(c.startTimeSeconds * 1000);
    const localTimeStr = date.toLocaleString('en-US', { timeZone: 'Asia/Kolkata' }) + ' IST';
    return {
      name: c.name,
      startTime: localTimeStr,
      durationHours: c.durationSeconds / 3600
    };
  });
  return JSON.stringify(schedule);
} catch(e) {
  return 'Failed to fetch contests: ' + e.message;
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://localhost:3000/api/pdf',
    body: {
      chat_id: $('Execute Workflow Trigger').first().json.chat_id,
      report_type: 'custom',
      title: query.title || 'DSA Interview Prep Notes',
      content: query.textContent || query.content
    },
    json: true
  });
  return JSON.stringify(response);
} catch(e) {
  return 'PDF generation failed: ' + e.message;
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://localhost:3000/api/dsa/solved',
    body: {
      chat_id: $('Execute Workflow Trigger').first().json.chat_id,
      platform: query.platform || 'leetcode',
      title_slug: query.titleSlug
    },
    json: true
  });
  return 'Problem marked as solved successfully!';
} catch(e) {
  return 'Failed to mark problem as solved: ' + e.message;
}
